import{_ as a,c as i,o as l,ae as o}from"./chunks/framework.Bw7rlmih.js";const p=JSON.parse('{"title":"19: Query and Search Language","description":"","frontmatter":{},"headers":[],"relativePath":"control-plane/19-query-and-search-language.md","filePath":"control-plane/19-query-and-search-language.md"}'),t={name:"control-plane/19-query-and-search-language.md"};function r(s,e,n,d,c,u){return l(),i("div",null,e[0]||(e[0]=[o(`<h1 id="_19-query-and-search-language" tabindex="-1">19: Query and Search Language <a class="header-anchor" href="#_19-query-and-search-language" aria-label="Permalink to &quot;19: Query and Search Language&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Konfigo needs a native query language to answer operational questions quickly:</p><ul><li>Where is this key used?</li><li>Which bundles reference this schema version?</li><li>What changed for a specific scope over time?</li></ul><p>This feature provides a consistent query interface across objects, versions, references, and drift findings.</p><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ul><li>Provide one query syntax for CLI and API.</li><li>Support both key/value search and graph-style dependency queries.</li><li>Enable fast impact analysis before promotions.</li></ul><h2 id="non-goals" tabindex="-1">Non-Goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-Goals&quot;">​</a></h2><ul><li>Replacing SQL or external analytics warehouses.</li><li>Arbitrary unbounded joins in phase 1.</li></ul><h2 id="query-model" tabindex="-1">Query Model <a class="header-anchor" href="#query-model" aria-label="Permalink to &quot;Query Model&quot;">​</a></h2><p>Two query modes:</p><ol><li><strong>Filter mode</strong>: object lists with predicates.</li><li><strong>Graph mode</strong>: relationship traversal (<code>where-used</code>, <code>depends-on</code>).</li></ol><h2 id="domain-entities" tabindex="-1">Domain Entities <a class="header-anchor" href="#domain-entities" aria-label="Permalink to &quot;Domain Entities&quot;">​</a></h2><ul><li>Schema</li><li>Template</li><li>Values</li><li>Bundle</li><li>Policy</li><li>Promotion</li><li>Drift finding</li><li>Event</li></ul><h2 id="example-queries" tabindex="-1">Example Queries <a class="header-anchor" href="#example-queries" aria-label="Permalink to &quot;Example Queries&quot;">​</a></h2><h3 id="filter-queries" tabindex="-1">Filter Queries <a class="header-anchor" href="#filter-queries" aria-label="Permalink to &quot;Filter Queries&quot;">​</a></h3><ul><li><code>bundle where scope = &quot;platform/payments/prod/api&quot; and status = &quot;published&quot;</code></li><li><code>values where scope like &quot;platform/payments/prod/%&quot; and key = &quot;DB_HOST&quot;</code></li><li><code>drift where severity in [&quot;critical&quot;,&quot;high&quot;] and status = &quot;open&quot;</code></li></ul><h3 id="graph-queries" tabindex="-1">Graph Queries <a class="header-anchor" href="#graph-queries" aria-label="Permalink to &quot;Graph Queries&quot;">​</a></h3><ul><li><code>where_used schema:payment:v7</code></li><li><code>depends_on bundle:payments-prod:v22</code></li><li><code>impact bundle:payments-prod:v22 -&gt; scope_prefix(&quot;platform/payments/prod/*&quot;)</code></li></ul><h2 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to &quot;CLI&quot;">​</a></h2><ul><li><code>konfigo query &quot;bundle where scope = &#39;platform/payments/prod/api&#39;&quot;</code></li><li><code>konfigo where-used schema:payment:v7</code></li><li><code>konfigo impact --bundle bundle:payments-prod:v22</code></li></ul><h2 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h2><ul><li><code>POST /v1/query/execute</code></li><li><code>POST /v1/query/where-used</code></li><li><code>POST /v1/query/impact</code></li></ul><h3 id="execute-query-example" tabindex="-1">Execute Query Example <a class="header-anchor" href="#execute-query-example" aria-label="Permalink to &quot;Execute Query Example&quot;">​</a></h3><p><code>POST /v1/query/execute</code></p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;query&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bundle where scope like &#39;platform/payments/prod/%&#39; and pinned = true&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;limit&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">200</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;cursor&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">null</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="language-design" tabindex="-1">Language Design <a class="header-anchor" href="#language-design" aria-label="Permalink to &quot;Language Design&quot;">​</a></h2><h3 id="syntax-rules-phase-1" tabindex="-1">Syntax Rules (Phase 1) <a class="header-anchor" href="#syntax-rules-phase-1" aria-label="Permalink to &quot;Syntax Rules (Phase 1)&quot;">​</a></h3><ul><li>Case-insensitive keywords.</li><li>String literals in single quotes.</li><li>Comparison operators: <code>=</code>, <code>!=</code>, <code>&lt;</code>, <code>&gt;</code>, <code>&lt;=</code>, <code>&gt;=</code>.</li><li>Boolean operators: <code>and</code>, <code>or</code>, <code>not</code>.</li><li>List operator: <code>in [ ... ]</code>.</li><li>Pattern operator: <code>like</code> with <code>%</code> wildcard.</li></ul><h3 id="reserved-functions" tabindex="-1">Reserved Functions <a class="header-anchor" href="#reserved-functions" aria-label="Permalink to &quot;Reserved Functions&quot;">​</a></h3><ul><li><code>scope_prefix(&#39;team/app/%&#39;)</code></li><li><code>age_lt(&#39;24h&#39;)</code></li><li><code>ref_eq(&#39;schema:payment:v7&#39;)</code></li></ul><h2 id="indexing-strategy" tabindex="-1">Indexing Strategy <a class="header-anchor" href="#indexing-strategy" aria-label="Permalink to &quot;Indexing Strategy&quot;">​</a></h2><p>Primary indexes:</p><ul><li><code>scope</code></li><li><code>objectType</code></li><li><code>version</code></li><li><code>createdAt</code></li><li><code>status</code></li></ul><p>Secondary inverted index:</p><ul><li>key path tokens</li><li>text fields for name/description</li></ul><p>Graph index:</p><ul><li>adjacency lists for references between object versions.</li></ul><h2 id="result-shape" tabindex="-1">Result Shape <a class="header-anchor" href="#result-shape" aria-label="Permalink to &quot;Result Shape&quot;">​</a></h2><p>Every result row contains:</p><ul><li><code>entityType</code></li><li><code>ref</code></li><li><code>scope</code></li><li><code>version</code></li><li><code>summary</code></li><li><code>links</code> (optional related refs)</li></ul><h2 id="security-and-access-control" tabindex="-1">Security and Access Control <a class="header-anchor" href="#security-and-access-control" aria-label="Permalink to &quot;Security and Access Control&quot;">​</a></h2><ul><li>Query engine applies scope-prefix authorization filter before returning any row.</li><li>Unauthorized rows are excluded, not masked.</li><li>Audit log stores original query and result count.</li></ul><h2 id="performance-targets" tabindex="-1">Performance Targets <a class="header-anchor" href="#performance-targets" aria-label="Permalink to &quot;Performance Targets&quot;">​</a></h2><ul><li>P95 filter query latency &lt; 300 ms for typical scope-filtered queries.</li><li>P95 graph traversal latency &lt; 800 ms for one-hop <code>where-used</code>.</li><li>Support pagination via cursor for large result sets.</li></ul><h2 id="rollout-plan" tabindex="-1">Rollout Plan <a class="header-anchor" href="#rollout-plan" aria-label="Permalink to &quot;Rollout Plan&quot;">​</a></h2><h3 id="phase-1" tabindex="-1">Phase 1 <a class="header-anchor" href="#phase-1" aria-label="Permalink to &quot;Phase 1&quot;">​</a></h3><ul><li>Filter mode on bundle/values/drift/event entities.</li><li>Basic <code>where-used</code> on schema/template refs.</li></ul><h3 id="phase-2" tabindex="-1">Phase 2 <a class="header-anchor" href="#phase-2" aria-label="Permalink to &quot;Phase 2&quot;">​</a></h3><ul><li>Impact analysis and transitive dependency traversal.</li><li>Saved queries.</li></ul><h3 id="phase-3" tabindex="-1">Phase 3 <a class="header-anchor" href="#phase-3" aria-label="Permalink to &quot;Phase 3&quot;">​</a></h3><ul><li>Query alerts (run query on schedule and emit event on match).</li></ul><h2 id="testing-strategy" tabindex="-1">Testing Strategy <a class="header-anchor" href="#testing-strategy" aria-label="Permalink to &quot;Testing Strategy&quot;">​</a></h2><ul><li>Parser and validator unit tests.</li><li>Query planner benchmark tests.</li><li>Authorization leak tests (cross-scope data isolation).</li><li>Snapshot tests for deterministic result ordering.</li></ul><h2 id="open-decisions" tabindex="-1">Open Decisions <a class="header-anchor" href="#open-decisions" aria-label="Permalink to &quot;Open Decisions&quot;">​</a></h2><ul><li>Whether to expose the same syntax to UI advanced search as-is.</li><li>Whether to allow user-defined macros in phase 2.</li></ul>`,56)]))}const q=a(t,[["render",r]]);export{p as __pageData,q as default};
